import{_ as t,o as a,c as s,ag as i,ah as o}from"./chunks/framework.D9bIGSBm.js";const u=JSON.parse('{"title":"安装","description":"","frontmatter":{},"headers":[],"relativePath":"guide/installation.md","filePath":"guide/installation.md"}'),l={name:"guide/installation.md"};function n(r,e,d,c,p,g){return a(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h1><h2 id="系统要求" tabindex="-1">系统要求 <a class="header-anchor" href="#系统要求" aria-label="Permalink to &quot;系统要求&quot;">​</a></h2><table tabindex="0"><thead><tr><th>要求</th><th>说明</th></tr></thead><tbody><tr><td>操作系统</td><td>Windows 10/11（x64 或 ARM64）；macOS（Intel 或 Apple Silicon）</td></tr><tr><td>磁盘空间</td><td>建议预留 1 GB 以上可用空间（应用本体 + 会话数据增长）</td></tr><tr><td>网络</td><td>下载安装包需联网访问 GitHub Releases；使用时需联网访问 AI 服务</td></tr><tr><td>前置依赖</td><td>需要安装 Claude Code CLI、Codex CLI 或 OpenCode CLI 中的至少一个（见<a href="/docs/guide/prerequisites.html">前置依赖</a>）</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Linux 暂未支持</p><p>当前版本（v0.7.0）不提供 Linux 安装包，Linux 用户请关注后续版本。</p></div><h2 id="windows-安装" tabindex="-1">Windows 安装 <a class="header-anchor" href="#windows-安装" aria-label="Permalink to &quot;Windows 安装&quot;">​</a></h2><ol><li>前往 <a href="https://github.com/LoongCode0/loongcode-release/releases/latest" target="_blank" rel="noreferrer">GitHub Releases（LoongCode0/loongcode-release）</a> 下载最新版安装包。</li><li>根据你的系统架构选择对应文件（不确定就选 x64，绝大多数电脑适用，ARM 设备也能兼容运行 x64 版）： <ul><li>普通电脑选 <code>LoongCode_*_x64-setup.exe</code></li><li>搭载高通芯片的 ARM 设备选 <code>LoongCode_*_arm64-setup.exe</code></li></ul></li><li>双击下载好的 <code>.exe</code> 文件，按安装向导提示完成安装。</li><li>安装完成后，桌面会出现 LoongCode 快捷方式，双击即可启动。</li></ol><p><img src="'+o+'" alt="截图：Windows 安装向导界面，安装进行中，显示安装进度条与目标路径选择步骤，突出进度条与路径输入框"></p><h3 id="处理「windows-已保护你的电脑」提示" tabindex="-1">处理「Windows 已保护你的电脑」提示 <a class="header-anchor" href="#处理「windows-已保护你的电脑」提示" aria-label="Permalink to &quot;处理「Windows 已保护你的电脑」提示&quot;">​</a></h3><p>由于 LoongCode 暂未进行操作系统级代码签名，Windows SmartScreen 可能会在首次安装时弹出如下提示。</p><p><img src="'+o+'" alt="截图：Windows SmartScreen「未知发布者」安全提示对话框，突出「更多信息」链接"></p><p>遇到此提示时：</p><ol><li>点击 <strong>更多信息</strong>（蓝色链接文字）。</li><li>点击随后出现的 <strong>仍要运行</strong> 按钮。</li><li>安装程序将正常继续。</li></ol><div class="warning custom-block"><p class="custom-block-title">为什么会出现这个提示？</p><p>LoongCode 暂未购买操作系统级代码签名证书，因此被 Windows 标记为「未知发布者」——这是 SmartScreen 对所有未签名软件的标准提示，不代表软件有问题。请确认你的下载链接直接来自官方 GitHub Releases（github.com/LoongCode0/loongcode-release），不经任何第三方转发，即可放心安装。</p></div><h2 id="macos-安装" tabindex="-1">macOS 安装 <a class="header-anchor" href="#macos-安装" aria-label="Permalink to &quot;macOS 安装&quot;">​</a></h2><ol><li>前往 <a href="https://github.com/LoongCode0/loongcode-release/releases/latest" target="_blank" rel="noreferrer">GitHub Releases（LoongCode0/loongcode-release）</a> 下载最新的 <code>.dmg</code> 文件（Intel 和 Apple Silicon 共用同一个通用包）。</li><li>双击 <code>.dmg</code> 文件，将弹出安装窗口。</li><li>把 <strong>LoongCode</strong> 图标拖入右侧的「<strong>应用程序</strong>」文件夹。</li><li>打开「应用程序」，双击 LoongCode 启动。</li></ol><p><img src="'+o+'" alt="截图：macOS DMG 安装窗口，展示将 LoongCode 拖入应用程序文件夹的操作界面"></p><h3 id="处理「无法验证开发者」或「已损坏」提示" tabindex="-1">处理「无法验证开发者」或「已损坏」提示 <a class="header-anchor" href="#处理「无法验证开发者」或「已损坏」提示" aria-label="Permalink to &quot;处理「无法验证开发者」或「已损坏」提示&quot;">​</a></h3><p>由于 LoongCode 暂未购买 Apple 代码签名证书，首次启动时 macOS 可能提示「无法验证开发者」或「已损坏，无法打开」。这是 macOS 对所有未签名应用的标准提示，不代表软件有问题——只要安装包直接下载自官方 GitHub Releases（github.com/LoongCode0/loongcode-release），即可放心按以下方式打开。</p><p><strong>方式一（推荐先试）</strong>：</p><ol><li>打开「<strong>应用程序</strong>」文件夹。</li><li>对 <strong>LoongCode</strong> 图标<strong>右键单击</strong>，在菜单中选择「<strong>打开</strong>」。</li><li>在弹出对话框中点击「<strong>打开</strong>」确认。</li></ol><p><strong>方式二</strong>（方式一无效时）：</p><p>打开「终端」应用，执行以下命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">xattr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -cr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /Applications/LoongCode.app</span></span></code></pre></div><p>执行完毕后切换到 Finder，在「应用程序」文件夹双击 LoongCode 即可正常打开。</p><div class="tip custom-block"><p class="custom-block-title">安装后无需重复操作</p><p>无论使用哪种方式完成首次打开，之后正常双击即可启动，不需要每次都执行这些步骤。</p></div><h2 id="自动更新" tabindex="-1">自动更新 <a class="header-anchor" href="#自动更新" aria-label="Permalink to &quot;自动更新&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">当前仅 Windows 支持自动更新</p><p>macOS 版暂不提供应用内自动更新，如需更新请手动下载新版安装包；平台支持范围以官方发布说明为准。</p></div><p>当 LoongCode 检测到新版本时，界面右上角会出现<strong>更新</strong>徽标。</p><ol><li>点击右上角的<strong>更新</strong>徽标。</li><li>在弹出的确认对话框中点击<strong>立即重启</strong>。</li></ol><p>确认后，LoongCode 会自动完成新版本的安装并重启，无需其他操作。</p><p><img src="'+o+'" alt="截图：LoongCode 标题栏右上角出现更新徽标，突出显示更新图标区域"></p><div class="tip custom-block"><p class="custom-block-title">下载的是完整安装包</p><p>自动更新下载的是完整安装包，文件较大，更新过程中请保持网络连接。</p></div><h2 id="卸载" tabindex="-1">卸载 <a class="header-anchor" href="#卸载" aria-label="Permalink to &quot;卸载&quot;">​</a></h2><p><strong>Windows</strong>：</p><ul><li>Windows 11：打开系统「<strong>设置 → 应用 → 已安装的应用</strong>」，找到 <strong>LoongCode</strong>，点击卸载。</li><li>Windows 10：打开系统「<strong>设置 → 应用 → 应用和功能</strong>」，找到 <strong>LoongCode</strong>，点击卸载。</li></ul><p><strong>macOS</strong>：</p><p>打开「<strong>应用程序</strong>」文件夹，将 <strong>LoongCode</strong> 拖入废纸篓，并清空废纸篓。</p><h3 id="数据目录" tabindex="-1">数据目录 <a class="header-anchor" href="#数据目录" aria-label="Permalink to &quot;数据目录&quot;">​</a></h3><p>卸载应用不会自动删除用户数据。LoongCode 的数据（对话记录、设置、数据库等）默认保存在：</p><ul><li>Windows：<code>%APPDATA%\\com.loongcode.desktop\\</code>（即 <code>C:\\Users\\&lt;用户名&gt;\\AppData\\Roaming\\com.loongcode.desktop\\</code>）</li><li>macOS：<code>~/Library/Application Support/com.loongcode.desktop/</code></li></ul><p>数据目录支持自定义，实际位置可在卸载前打开「设置 → 常规 → <strong>数据目录</strong>」查看。如需彻底清除所有数据，卸载后手动删除该目录即可。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>LoongCode 装好后，还需要准备它的「引擎」——前往<a href="/docs/guide/prerequisites.html">前置依赖</a>页面安装 Claude Code CLI。</p>',43)])])}const m=t(l,[["render",n]]);export{u as __pageData,m as default};
